// ═══════════════════════════════════════════════════
//  THEME
// ═══════════════════════════════════════════════════
function getTheme() { return localStorage.getItem('na_theme') || 'dark'; }
function applyTheme(t) {
  document.documentElement.setAttribute('data-theme', t);
  localStorage.setItem('na_theme', t);
}
function toggleTheme() {
  const cur = getTheme();
  applyTheme(cur === 'dark' ? 'light' : 'dark');
}
applyTheme(getTheme());

// ═══════════════════════════════════════════════════
//  APP STATE
// ═══════════════════════════════════════════════════
const S = {
  q:'', page:1, pp:10, sort:'cited_by_count:desc',
  searchMode:'all',
  fQuartile:'', fType:'', fYearFrom:'', fYearTo:'',
  fLang:'', fAuthor:'', fInstitution:'',
  results:[], total:0, selected:new Set(), jCache:{}
};

// ═══════════════════════════════════════════════════
//  SEARCH MODE
// ═══════════════════════════════════════════════════
function setSearchMode(mode) {
  S.searchMode = mode;
  const map = { all:'sm_all', title_and_abstract:'sm_ta', title:'sm_title' };
  Object.entries(map).forEach(([m, id]) => {
    document.getElementById(id)?.classList.toggle('on', m === mode);
  });
  const hints = {
    all: 'Judul, penulis, topik, kata kunci, atau DOI...',
    title_and_abstract: 'Cari di judul & abstrak...',
    title: 'Cari di judul paper...'
  };
  document.getElementById('q').placeholder = hints[mode] || hints.all;
  if (S.q) { S.page=1; doSearch(); }
}

// ═══════════════════════════════════════════════════
//  SEARCH
// ═══════════════════════════════════════════════════
async function triggerSearch() {
  S.q = document.getElementById('q').value.trim();
  S.sort = document.getElementById('sortSel').value;
  if (!S.q) return;
  S.page = 1;
  await doSearch();
}

let _searchId = 0;

async function doSearch() {
  if (!S.q) return;
  const myId = ++_searchId;
  const btn = document.getElementById('goBtn');
  btn.disabled = true; btn.textContent = '…';
  document.getElementById('pageHeroWrap').classList.add('has-results');
  showLoading();
  document.getElementById('rbar').style.display = 'flex';

  const url = buildURL();
  try {
    const res = await fetch(url);
    const data = await res.json();
    if (myId !== _searchId) return;
    S.results = data.results || [];
    S.total = data.meta?.count || 0;
    renderResults();
    enrichCards(myId);
    if (S.page === 1) fetchTrend(S.q);
  } catch(e) {
    if (myId !== _searchId) return;
    document.getElementById('out').innerHTML =
      `<div class="empty"><div class="empty-ic">⚠️</div><h3>Gagal memuat</h3><p>Periksa koneksi internet Anda</p></div>`;
  }
  btn.disabled = false; btn.textContent = 'CARI';
}

function buildURL() {
  let f = 'is_oa:true';
  if (S.fYearFrom) f += `,publication_year:>${+S.fYearFrom-1}`;
  if (S.fYearTo)   f += `,publication_year:<${+S.fYearTo+1}`;
  if (S.fType)     f += `,type:${S.fType}`;
  if (S.fLang)     f += `,language:${S.fLang}`;
  if (S.fAuthor)   f += `,raw_author_name.search:${encodeURIComponent(S.fAuthor)}`;
  if (S.fInstitution) f += `,authorships.institutions.display_name.search:${encodeURIComponent(S.fInstitution)}`;

  const qEnc = encodeURIComponent(S.q);
  let searchParam = '';
  if (S.searchMode === 'all') {
    searchParam = `&search=${qEnc}`;
  } else if (S.searchMode === 'title_and_abstract') {
    f += `,title_and_abstract.search:${qEnc}`;
  } else if (S.searchMode === 'title') {
    f += `,title.search:${qEnc}`;
  }

  return [
    'https://api.openalex.org/works',
    `?filter=${f}`, searchParam,
    `&sort=${S.sort}`,
    `&per-page=${S.pp}&page=${S.page}`,
    '&select=id,doi,title,authorships,publication_year,primary_location,open_access,cited_by_count,type,abstract_inverted_index,best_oa_location,language',
    '&mailto=scholarhunt@app.id'
  ].join('');
}

function hasActiveFilters() {
  return [S.fType,S.fYearFrom,S.fYearTo,S.fLang,S.fAuthor,S.fInstitution].some(v => v && v !== '');
}

// ═══════════════════════════════════════════════════
//  RENDER
// ═══════════════════════════════════════════════════
function renderResults() {
  const pages = Math.min(Math.ceil(S.total / S.pp), 50);
  document.getElementById('rcnt').innerHTML =
    `<strong>${S.total.toLocaleString('id-ID')}</strong> paper ditemukan`;

  if (!S.results.length) {
    document.getElementById('out').innerHTML =
      `<div class="empty"><div class="empty-ic">📭</div><h3>Tidak ada artikel</h3><p>${hasActiveFilters()?'Coba filter atau kata kunci lain':'Coba kata kunci berbeda'}</p></div>`;
    return;
  }

  let html = '';
  S.results.forEach((w, i) => {
    const doi = w.doi?.replace('https://doi.org/','') || null;
    const issn = w.primary_location?.source?.issn_l || null;
    const pdf = w.best_oa_location?.pdf_url || w.open_access?.oa_url || null;
    const authors = (w.authorships||[]).slice(0,4).map(a=>a.author?.display_name||'').filter(Boolean).join(', ');
    const moreA = (w.authorships?.length||0)>4 ? ` +${w.authorships.length-4}` : '';
    const journal = w.primary_location?.source?.display_name || '';
    const abstract = w.abstract_inverted_index ? rebuildAbstract(w.abstract_inverted_index).slice(0,360) : '';
    const key = doi || w.id;
    const sel = S.selected.has(key);

    const allIssns = [];
    if (issn) allIssns.push(issn);
    (w.primary_location?.source?.issn||[]).forEach(v => { if(v && !allIssns.includes(v)) allIssns.push(v); });

    let sintaInfo = null;
    for (const iv of allIssns) { if (SINTA_DB[iv]) { sintaInfo = SINTA_DB[iv]; break; } }
    w._issn = issn; w._allIssns = allIssns;
    w._sintaGrade = sintaInfo?sintaInfo[0]:null;
    w._sintaName  = sintaInfo?sintaInfo[1]:null;

    html += `
    <div class="card" id="card_${eId(key)}" data-idx="${i}" style="animation-delay:${i*22}ms">
      <div class="cb ${sel?'on':''}" id="cb_${eId(key)}" onclick="toggleSel('${eKey(key)}')">
        ${sel?'✓':''}
      </div>
      <div class="badges" id="badges_${eId(key)}">
        ${w.open_access?.is_oa?'<span class="b b-oa">◉ Open Access</span>':''}
        <span class="b b-load" id="sjrb_${eId(key)}">⏳ SJR…</span>
        ${sintaInfo?`<span class="b b-s${sintaInfo[0]}">SINTA ${sintaInfo[0]}</span>`:''}
        <span class="b b-yr">${w.publication_year||'?'}</span>
        <span class="b b-tp">${fmtType(w.type)}</span>
        <span id="retrbadge_${eId(key)}"></span>
      </div>
      <div id="retrdetail_${eId(key)}"></div>
      <div class="ctitle" onclick="${doi?`window.open('https://doi.org/${doi}','_blank')`:''}">
        ${esc(w.title||'Untitled')}
      </div>
      ${authors?`<div class="cauth">👤 ${esc(authors)}${moreA?`<span style="color:var(--t3)"> ${moreA}</span>`:''}</div>`:''}
      ${journal?`<div class="cjrnl">📰 <a href="${w.primary_location?.source?.id?'https://openalex.org/'+w.primary_location.source.id:'#'}" target="_blank">${esc(journal)}</a>${issn?` <span style="color:var(--t3);font-size:.57rem">· ISSN ${issn}</span>`:''}</div>`:''}
      ${abstract?`<div class="cabst">${esc(abstract)}${abstract.length>=360?'…':''}</div>`:''}
      <div class="cfoot">
        <div class="cmeta">
          <div class="cm">📌 ${(w.cited_by_count||0).toLocaleString('id-ID')} sitasi</div>
          ${doi?`<div class="cm">🔗 ${doi.slice(0,28)}${doi.length>28?'…':''}</div>`:''}
        </div>
        <div class="cacts">
          ${pdf?`<a href="${pdf}" target="_blank" class="btn btn-pdf">⬇ PDF</a>`:''}
          ${doi?`<a href="https://doi.org/${doi}" target="_blank" class="btn btn-doi">DOI →</a>`:''}
          <button class="btn btn-detail" onclick="openDetail(${i})">🔗 Related</button>
          <button class="btn btn-bib" onclick="exportOne(${i})">📋 BibTeX</button>
          <button class="btn btn-save ${isSaved(key)?'saved':''}" id="savebtn_${eId(key)}" onclick="toggleSave(${i})">${isSaved(key)?'🔖 Tersimpan':'🔖 Simpan'}</button>
        </div>
      </div>
    </div>`;
  });

  html += renderPager(pages);
  document.getElementById('out').innerHTML = html;
}

// ═══════════════════════════════════════════════════
//  JOURNAL ENRICHMENT
// ═══════════════════════════════════════════════════
async function enrichCards(mySearchId) {
  for (let i=0; i<S.results.length; i++) {
    if (mySearchId !== _searchId) return;
    const w = S.results[i];
    const allIssns = w._allIssns || [];
    const doi = w.doi?.replace('https://doi.org/','') || null;
    const key = doi || w.id;
    const id = eId(key);

    let sjrQ = null;
    const toFetch = allIssns.find(iv => S.jCache[iv] === undefined);
    if (toFetch) {
      S.jCache[toFetch] = null;
      try {
        const r = await fetch(`https://api.openalex.org/sources?filter=issn:${toFetch}&select=apc_usd&per-page=1&mailto=scholarhunt@app.id`);
        if (mySearchId !== _searchId) return;
        const d = await r.json();
        const src = d?.results?.[0];
        let q = null;
        if (src?.apc_usd >= 3000) q=1;
        else if (src?.apc_usd >= 1500) q=2;
        else if (src?.apc_usd >= 500) q=3;
        else if (src?.apc_usd > 0) q=4;
        S.jCache[toFetch] = { q };
      } catch(e) { S.jCache[toFetch] = {q:null}; }
    }
    for (const iv of allIssns) { if (S.jCache[iv]?.q) { sjrQ = S.jCache[iv].q; break; } }
    w._sjrQ = sjrQ;

    const sjrEl = document.getElementById(`sjrb_${id}`);
    const cardEl = document.getElementById(`card_${id}`);
    if (sjrEl) {
      if (sjrQ) {
        sjrEl.className = `b b-q${sjrQ}`;
        sjrEl.textContent = `Q${sjrQ} Scimago`;
        if (cardEl) { cardEl.classList.remove('q1','q2','q3','q4'); cardEl.classList.add(`q${sjrQ}`); }
      } else {
        sjrEl.className=''; sjrEl.textContent='';
      }
    }
    await sleep(80);
    if (doi) checkRetraction(doi, id);
  }
}

// ═══════════════════════════════════════════════════
//  SELECTION + BIBTEX
// ═══════════════════════════════════════════════════
function toggleSel(key) {
  S.selected.has(key) ? S.selected.delete(key) : S.selected.add(key);
  const id = eId(key);
  const el = document.getElementById(`cb_${id}`);
  if (el) { el.classList.toggle('on', S.selected.has(key)); el.textContent = S.selected.has(key)?'✓':''; }
  updateXBar();
}
function clearSel() {
  S.selected.clear();
  document.querySelectorAll('.cb').forEach(el => { el.classList.remove('on'); el.textContent=''; });
  updateXBar();
}
function updateXBar() {
  const n = S.selected.size;
  document.getElementById('xbar').classList.toggle('show', n>0);
  document.getElementById('xcount').textContent = n;
  const ep = document.getElementById('exportPill');
  ep.style.display = n>0 ? 'inline-flex' : 'none';
  document.getElementById('selCnt').textContent = n;
}

function buildBib(papers) {
  return papers.map(w => {
    const doi = w.doi?.replace('https://doi.org/','') || null;
    const authors = (w.authorships||[]).map(a => {
      const n = a.author?.display_name||'';
      const parts = n.split(' ');
      return parts.length>1 ? `${parts[parts.length-1]}, ${parts.slice(0,-1).join(' ')}` : n;
    }).join(' and ');
    const yr = w.publication_year||'';
    const journal = w.primary_location?.source?.display_name||'';
    const title = (w.title||'').replace(/[{}]/g,'');
    const type = ['article','review'].includes(w.type) ? '@article' : '@misc';
    const bk = ((authors.split(',')[0]||'anon').replace(/\s+/g,'').toLowerCase()) + yr;
    return `${type}{${bk},\n  title   = {${title}},\n  author  = {${authors}},\n  journal = {${journal}},\n  year    = {${yr}},${doi?`\n  doi     = {${doi}},`:''}\n  url     = {${w.doi||w.id||''}},\n  note    = {Open Access}\n}`;
  }).join('\n\n');
}

function exportOne(i) {
  document.getElementById('bibContent').textContent = buildBib([S.results[i]]);
  document.getElementById('modal').classList.add('show');
}
function openModal() {
  const sel = S.results.filter(w => {
    const key = w.doi?.replace('https://doi.org/','') || w.id;
    return S.selected.has(key);
  });
  document.getElementById('bibContent').textContent = buildBib(sel.length?sel:S.results);
  document.getElementById('modal').classList.add('show');
}
function closeOverlay(e) {
  if (e.target === document.getElementById('modal')) document.getElementById('modal').classList.remove('show');
}
function copyBib() {
  navigator.clipboard.writeText(document.getElementById('bibContent').textContent)
    .then(()=>toast('✓ BibTeX disalin!'));
}
function dlBib() {
  const blob = new Blob([document.getElementById('bibContent').textContent],{type:'text/plain'});
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob); a.download = `nyari-artikel-${S.q.slice(0,20).replace(/\s+/g,'-')}.bib`; a.click();
  toast('⬇ File .bib diunduh!');
}

// ═══════════════════════════════════════════════════
//  PAGINATION + FILTERS
// ═══════════════════════════════════════════════════
function renderPager(totalPgs) {
  if (totalPgs <= 1) return '';
  const p=S.page, s=Math.max(1,p-2), e=Math.min(totalPgs,p+2);
  let btns='';
  if(s>1) btns+=`<button class="pg" onclick="goPage(1)">1</button>`;
  if(s>2) btns+=`<span class="pg-sep">…</span>`;
  for(let x=s;x<=e;x++) btns+=`<button class="pg ${x===p?'on':''}" onclick="goPage(${x})">${x}</button>`;
  if(e<totalPgs-1) btns+=`<span class="pg-sep">…</span>`;
  if(e<totalPgs) btns+=`<button class="pg" onclick="goPage(${totalPgs})">${totalPgs}</button>`;
  return `<div class="pager">
    <button class="pg" onclick="goPage(${p-1})" ${p<=1?'disabled':''}>← Prev</button>
    ${btns}
    <button class="pg" onclick="goPage(${p+1})" ${p>=totalPgs?'disabled':''}>Next →</button>
  </div>`;
}
function goPage(p) { S.page=p; doSearch(); window.scrollTo({top:0,behavior:'smooth'}); }

function toggleFilterPanel() {
  document.getElementById('filterPanel').classList.toggle('open');
  document.getElementById('ftoggleIcon').classList.toggle('open');
}
function resetFilters() {
  ['fQuartile','fType','fYearFrom','fYearTo','fLang'].forEach(id => document.getElementById(id).value='');
  ['fAuthor','fInstitution'].forEach(id => document.getElementById(id).value='');
  S.fQuartile=S.fType=S.fYearFrom=S.fYearTo=S.fLang=S.fAuthor=S.fInstitution='';
  updateFilterBadge();
}
function applyFilters() {
  S.fQuartile    = document.getElementById('fQuartile').value;
  S.fType        = document.getElementById('fType').value;
  S.fYearFrom    = document.getElementById('fYearFrom').value;
  S.fYearTo      = document.getElementById('fYearTo').value;
  S.fLang        = document.getElementById('fLang').value;
  S.fAuthor      = document.getElementById('fAuthor').value.trim();
  S.fInstitution = document.getElementById('fInstitution').value.trim();
  updateFilterBadge();
  document.getElementById('filterPanel').classList.remove('open');
  document.getElementById('ftoggleIcon').classList.remove('open');
  if (S.q) { S.page=1; doSearch(); }
}
function updateFilterBadge() {
  const active = [S.fType,S.fYearFrom,S.fYearTo,S.fLang,S.fAuthor,S.fInstitution].filter(v=>v&&v!=='').length;
  const pill = document.getElementById('filterPill');
  const label = document.getElementById('filterActiveLabel');
  pill.classList.toggle('has-active', active>0);
  label.style.display = active>0 ? 'inline' : 'none';
  if (active>0) label.textContent = active;
}

(function populateYears(){
  const cur = new Date().getFullYear();
  const from = document.getElementById('fYearFrom');
  const to   = document.getElementById('fYearTo');
  for(let y=cur;y>=1990;y--){
    from.innerHTML += `<option value="${y}">${y}</option>`;
    to.innerHTML   += `<option value="${y}">${y}</option>`;
  }
})();

// ═══════════════════════════════════════════════════
//  TREND CHART
// ═══════════════════════════════════════════════════
let _trendData=[], _chartMode='bar';

async function fetchTrend(q) {
  const wrap=document.getElementById('trendWrap');
  const loading=document.getElementById('trendLoading');
  const svgWrap=document.getElementById('trendSvgWrap');
  wrap.style.display='block'; loading.style.display='block';
  svgWrap.innerHTML=''; document.getElementById('trendStats').innerHTML='';
  document.getElementById('trendTopic').textContent = q.length>36?q.slice(0,36)+'…':q;

  try {
    let f='is_oa:true';
    if(S.fYearFrom) f+=`,publication_year:>${+S.fYearFrom-1}`;
    if(S.fYearTo)   f+=`,publication_year:<${+S.fYearTo+1}`;
    if(S.fType)     f+=`,type:${S.fType}`;
    const url=`https://api.openalex.org/works?search=${encodeURIComponent(q)}&filter=${f}&group_by=publication_year&per-page=200&mailto=scholarhunt@app.id`;
    const data=(await (await fetch(url)).json());
    const curYear=new Date().getFullYear();
    const raw=(data.group_by||[]).map(g=>({year:+g.key,count:g.count})).filter(d=>d.year>=1990&&d.year<=curYear).sort((a,b)=>a.year-b.year);
    _trendData=raw; loading.style.display='none';
    if(!raw.length){svgWrap.innerHTML='<div class="trend-loading">Tidak ada data tren</div>';return;}
    renderTrendStats(raw); renderTrendChart(raw,_chartMode);
  } catch(e){ loading.style.display='none'; svgWrap.innerHTML='<div class="trend-loading">Gagal memuat tren</div>'; }
}

function renderTrendStats(data){
  const total=data.reduce((s,d)=>s+d.count,0);
  const peak=data.reduce((a,b)=>b.count>a.count?b:a,data[0]);
  const recent=[...data].slice(-5).reduce((s,d)=>s+d.count,0);
  const prev5=[...data].slice(-10,-5).reduce((s,d)=>s+d.count,0);
  const growth=prev5>0?Math.round((recent-prev5)/prev5*100):null;
  document.getElementById('trendStats').innerHTML=`
    <div class="tstat"><div class="tstat-val">${fmtNum(total)}</div><div class="tstat-lbl">Total</div></div>
    <div class="tstat"><div class="tstat-val">${peak.year}</div><div class="tstat-lbl">Puncak</div></div>
    ${growth!==null?`<div class="tstat"><div class="tstat-val" style="color:${growth>=0?'var(--green)':'var(--rose)'}">${growth>=0?'+':''}${growth}%</div><div class="tstat-lbl">5 Thn</div></div>`:''}`;
}
function fmtNum(n){if(n>=1e6)return(n/1e6).toFixed(1)+'M';if(n>=1000)return(n/1000).toFixed(1)+'K';return n.toLocaleString('id-ID');}

function setChartMode(mode){
  _chartMode=mode;
  document.getElementById('ttBar').classList.toggle('on',mode==='bar');
  document.getElementById('ttLine').classList.toggle('on',mode==='line');
  if(_trendData.length) renderTrendChart(_trendData,mode);
}

function renderTrendChart(data,mode){
  const W=860,H=200,PL=48,PR=12,PT=10,PB=36;
  const cW=W-PL-PR,cH=H-PT-PB;
  const maxC=Math.max(...data.map(d=>d.count));
  const peakYear=data.reduce((a,b)=>b.count>a.count?b:a,data[0]).year;
  const n=data.length;
  const barW=Math.max(4,cW/n-2);
  let grids='',yLabels='';
  for(let i=0;i<=4;i++){
    const v=maxC*i/4,y=PT+cH-(cH*i/4);
    grids+=`<line class="trend-grid" x1="${PL}" x2="${W-PR}" y1="${y}" y2="${y}"/>`;
    yLabels+=`<text class="trend-ylabel" x="${PL-5}" y="${y+3}">${fmtNum(Math.round(v))}</text>`;
  }
  let chartBody='';
  if(mode==='bar'){
    data.forEach((d,i)=>{
      const x=PL+(i/(n-1||1))*(cW-barW)+barW/2-barW/2;
      const bH=Math.max(2,(d.count/maxC)*cH),y=PT+cH-bH;
      const cls=d.year===peakYear?'peak':(i>=n-3?'recent':'');
      chartBody+=`<rect class="trend-bar ${cls}" x="${x.toFixed(1)}" y="${y.toFixed(1)}" width="${barW.toFixed(1)}" height="${bH.toFixed(1)}" rx="2"
        onmouseenter="showTrendTip(event,${d.year},${d.count})" onmouseleave="hideTrendTip()"/>`;
    });
  } else {
    const pts=data.map((d,i)=>[PL+(i/(n-1||1))*cW, PT+cH-(d.count/maxC)*cH]);
    const areaPath=`M${pts[0][0]},${PT+cH} `+pts.map(p=>`L${p[0].toFixed(1)},${p[1].toFixed(1)}`).join(' ')+` L${pts[pts.length-1][0]},${PT+cH} Z`;
    const linePath=`M${pts.map(p=>`${p[0].toFixed(1)},${p[1].toFixed(1)}`).join(' L')}`;
    chartBody+=`<defs><linearGradient id="trendGrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="var(--gold)" stop-opacity=".5"/><stop offset="100%" stop-color="var(--gold)" stop-opacity="0"/></linearGradient></defs>`;
    chartBody+=`<path class="trend-area" d="${areaPath}"/><path class="trend-line" d="${linePath}"/>`;
    pts.forEach((p,i)=>{ chartBody+=`<circle class="trend-dot" cx="${p[0].toFixed(1)}" cy="${p[1].toFixed(1)}" r="3" onmouseenter="showTrendTip(event,${data[i].year},${data[i].count})" onmouseleave="hideTrendTip()"/>`; });
  }
  const step=n<=15?1:n<=25?2:5;
  let xLabels='';
  data.forEach((d,i)=>{
    if(i%step!==0&&i!==n-1)return;
    const x=PL+(i/(n-1||1))*cW;
    xLabels+=`<text class="trend-xlabel" x="${x.toFixed(1)}" y="${H-4}">${d.year}</text>`;
  });
  document.getElementById('trendSvgWrap').innerHTML=`<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">${grids}${yLabels}${chartBody}${xLabels}</svg>`;
}
function showTrendTip(e,year,count){
  const tip=document.getElementById('trendTip');
  const wrap=document.getElementById('trendWrap');
  const rect=wrap.getBoundingClientRect();
  tip.textContent=`${year}  ·  ${count.toLocaleString('id-ID')} paper`;
  tip.classList.add('show');
  tip.style.left=Math.min(e.clientX-rect.left+10,rect.width-160)+'px';
  tip.style.top=(e.clientY-rect.top-36)+'px';
}
function hideTrendTip(){ document.getElementById('trendTip').classList.remove('show'); }

// ═══════════════════════════════════════════════════
//  RETRACTION CHECK
// ═══════════════════════════════════════════════════
const _retrCache={};
async function checkRetraction(doi,id){
  if(_retrCache[doi]!==undefined){applyRetractionUI(doi,id,_retrCache[doi]);return;}
  try{
    const r=await fetch(`https://api.retractionwatch.com/api/article?doi=${encodeURIComponent(doi)}`,{headers:{'User-Agent':'NyariArtikel/3.0'}});
    if(!r.ok){_retrCache[doi]=null;return;}
    const data=await r.json();
    const entry=Array.isArray(data)?data[0]:(data?.doi?data:null);
    _retrCache[doi]=entry||null;
    applyRetractionUI(doi,id,entry||null);
  }catch(e){_retrCache[doi]=null;}
}
function applyRetractionUI(doi,id,entry){
  if(!entry)return;
  const badgeEl=document.getElementById(`retrbadge_${id}`);
  const detailEl=document.getElementById(`retrdetail_${id}`);
  const cardEl=document.getElementById(`card_${id}`);
  if(!badgeEl)return;
  const isRetracted=entry.RetractionDate||entry.retracted;
  const isConcern=entry.Nature&&entry.Nature.toLowerCase().includes('concern');
  const label=isRetracted?'⚠ RETRAKSI':isConcern?'⚠ KEKHAWATIRAN':'⚠ NOTICE';
  badgeEl.innerHTML=`<span class="b b-retracted">${label}</span>`;
  if(cardEl)cardEl.classList.add('retracted');
  const reason=entry.Reason||entry.reason||'';
  const date=entry.RetractionDate||entry.retraction_date||'';
  if(detailEl&&(reason||date)){
    detailEl.innerHTML=`<div class="retract-detail"><strong>${isRetracted?'⚠ Paper ini telah diretraksi':'⚠ Expression of Concern'}${date?' ('+date.slice(0,10)+')':''}</strong>${reason?`<br>${esc(reason.slice(0,220))}${reason.length>220?'…':''}`:''}<br><a href="https://doi.org/${doi}" target="_blank" style="color:var(--rose);font-size:.7rem">Lihat detail →</a></div>`;
  }
  const saved=loadKoleksi();
  const idx=saved.findIndex(p=>(p.doi||p.id)===doi);
  if(idx>=0){saved[idx]._retracted=true;saved[idx]._retrLabel=label;saveKoleksi(saved);renderKoleksiPanel();}
}

// ═══════════════════════════════════════════════════
//  KOLEKSI
// ═══════════════════════════════════════════════════
const KOLEKSI_KEY='nyariartikel_koleksi';
function loadKoleksi(){try{return JSON.parse(localStorage.getItem(KOLEKSI_KEY)||'[]');}catch(e){return[];}}
function saveKoleksi(arr){localStorage.setItem(KOLEKSI_KEY,JSON.stringify(arr));updateKoleksiBadge();}
function updateKoleksiBadge(){
  const n=loadKoleksi().length;
  const el=document.getElementById('koleksiCount');
  if(el){el.textContent=n;el.style.display=n>0?'inline':'none';}
  const hel=document.getElementById('koleksiHeadCount');
  if(hel)hel.textContent=n;
}
function isSaved(key){return loadKoleksi().some(p=>(p.doi||p.id)===key);}

function toggleSave(idx){
  const w=S.results[idx]; if(!w)return;
  const doi=w.doi?.replace('https://doi.org/','')||null;
  const key=doi||w.id; const id=eId(key);
  let saved=loadKoleksi();
  const exists=saved.findIndex(p=>(p.doi||p.id)===key);
  if(exists>=0){
    saved.splice(exists,1); saveKoleksi(saved); toast('🗑 Dihapus dari koleksi');
    const btn=document.getElementById(`savebtn_${id}`);
    if(btn){btn.classList.remove('saved');btn.textContent='🔖 Simpan';}
  } else {
    const authors=(w.authorships||[]).slice(0,3).map(a=>a.author?.display_name||'').filter(Boolean).join(', ');
    const abstract=w.abstract_inverted_index?rebuildAbstract(w.abstract_inverted_index).slice(0,300):'';
    const pdf=w.best_oa_location?.pdf_url||w.open_access?.oa_url||null;
    saved.unshift({doi,id:w.id,title:w.title||'Untitled',authors,journal:w.primary_location?.source?.display_name||'',year:w.publication_year||'',cited:w.cited_by_count||0,pdf,abstract,savedAt:new Date().toISOString(),_retracted:false,_retrLabel:''});
    saveKoleksi(saved); toast('🔖 Disimpan ke koleksi!');
    const btn=document.getElementById(`savebtn_${id}`);
    if(btn){btn.classList.add('saved');btn.textContent='🔖 Tersimpan';}
  }
  if(document.getElementById('koleksiOverlay').classList.contains('show'))renderKoleksiPanel();
}

function openKoleksi(){renderKoleksiPanel();document.getElementById('koleksiOverlay').classList.add('show');}
function closeKoleksi(){document.getElementById('koleksiOverlay').classList.remove('show');}
function closeKoleksiOutside(e){if(e.target===document.getElementById('koleksiOverlay'))closeKoleksi();}

function renderKoleksiPanel(){
  const saved=loadKoleksi();
  const body=document.getElementById('koleksiBody');
  if(!body)return;
  updateKoleksiBadge();
  if(!saved.length){body.innerHTML=`<div class="koleksi-empty"><div class="ei">🔖</div>Belum ada artikel tersimpan.<br>Klik <strong>Simpan</strong> di kartu artikel.</div>`;return;}
  body.innerHTML=saved.map((p,i)=>{
    const key=p.doi||p.id;
    const href=p.doi?`https://doi.org/${p.doi}`:(p.id||'#');
    return `<div class="kcard" id="kcard_${i}">
      ${p._retracted?`<div class="koleksi-retracted-badge">⚠ ${p._retrLabel||'RETRAKSI'}</div>`:''}
      <button class="kcard-del" onclick="removeFromKoleksi('${eKey(key)}')" title="Hapus">✕</button>
      <div class="kcard-title" onclick="window.open('${href}','_blank')">${esc(p.title)}</div>
      <div class="kcard-meta">
        ${p.authors?`👤 ${esc(p.authors)}<br>`:''}
        ${p.journal?`📰 ${esc(p.journal)} · `:''}${p.year||''}
        ${p.cited?` · 📌 ${p.cited.toLocaleString('id-ID')} sitasi`:''}
        <br>🗓 ${new Date(p.savedAt).toLocaleDateString('id-ID',{day:'numeric',month:'short',year:'numeric'})}
      </div>
      <div class="kcard-acts">
        ${p.pdf?`<a href="${p.pdf}" target="_blank" class="btn btn-pdf" style="font-size:.58rem;padding:4px 9px">⬇ PDF</a>`:''}
        ${p.doi?`<a href="https://doi.org/${p.doi}" target="_blank" class="btn btn-doi" style="font-size:.58rem;padding:4px 9px">DOI →</a>`:''}
      </div>
    </div>`;
  }).join('');
}
function removeFromKoleksi(key){
  let saved=loadKoleksi().filter(p=>(p.doi||p.id)!==key);
  saveKoleksi(saved); renderKoleksiPanel();
  const btn=document.getElementById(`savebtn_${eId(key)}`);
  if(btn){btn.classList.remove('saved');btn.textContent='🔖 Simpan';}
  toast('🗑 Dihapus dari koleksi');
}
function clearKoleksi(){
  if(!confirm('Hapus semua artikel dari koleksi?'))return;
  saveKoleksi([]); renderKoleksiPanel();
  document.querySelectorAll('.btn-save.saved').forEach(btn=>{btn.classList.remove('saved');btn.textContent='🔖 Simpan';});
  toast('🗑 Koleksi dikosongkan');
}
function exportKoleksiBib(){
  const saved=loadKoleksi();
  if(!saved.length){toast('Koleksi masih kosong');return;}
  const papers=saved.map(p=>({doi:p.doi?'https://doi.org/'+p.doi:null,id:p.id,title:p.title,authorships:(p.authors||'').split(', ').map(n=>({author:{display_name:n}})),publication_year:p.year,primary_location:{source:{display_name:p.journal}},type:'article'}));
  document.getElementById('bibContent').textContent=buildBib(papers);
  document.getElementById('modal').classList.add('show');
}
updateKoleksiBadge();

